@@ -0,0 +1,48 @@
+import { createTransport, Transporter } from 'nodemailer';
+
+interface EmailOptions {
+  to: string;
+  subject: string;
+  html: string;
+  from?: string;
+}
+
+interface RetryConfig {
+  maxRetries: number;
+  delayMs: number;
+}
+
+const DEFAULT_RETRY: RetryConfig = { maxRetries: 3, delayMs: 1000 };
+
+export class EmailService {
+  private transporter: Transporter;
+  private retryConfig: RetryConfig;
+
+  constructor(retryConfig?: Partial<RetryConfig>) {
+    this.retryConfig = { ...DEFAULT_RETRY, ...retryConfig };
+    this.transporter = createTransport({
+      host: process.env.SMTP_HOST ?? 'localhost',
+      port: Number(process.env.SMTP_PORT) || 587,
+      secure: process.env.SMTP_SECURE === 'true',
+      auth: {
+        user: process.env.SMTP_USER ?? '',
+        pass: process.env.SMTP_PASS ?? '',
+      },
+    });
+  }
+
+  async send(options: EmailOptions): Promise<boolean> {
+    const from = options.from ?? process.env.SMTP_FROM ?? 'noreply@example.com';
+    let lastError: Error | null = null;
+
+    for (let attempt = 0; attempt <= this.retryConfig.maxRetries; attempt++) {
+      try {
+        await this.transporter.sendMail({ from, to: options.to, subject: options.subject, html: options.html });
+        return true;
+      } catch (err) {
+        lastError = err instanceof Error ? err : new Error(String(err));
+        if (attempt < this.retryConfig.maxRetries) {
+          await new Promise((resolve) => setTimeout(resolve, this.retryConfig.delayMs * (attempt + 1)));
+        }
+      }
+    }
+
+    throw lastError ?? new Error('Failed to send email');
+  }
+}
